# Deterministic on the ref Pi across 5 back-to-back runs but time/state-variant
# in the wild; deliberately left out so they fall through to Tier 2:
#   date
#   uptime
#   free -m
#   free -h
#   df -h
#   df -i
#   ls /tmp
#   ls -la /tmp

# Identity-polluted: captured as pi user on ref Pi but red team logs in as root,
# so the pi-captured value is wrong for root (e.g. "Permission denied" vs "No
# such file", "no crontab for pi" vs "no crontab for root"). Tier 2 can fake
# these correctly with an LLM prompt that knows we are root; re-capture as root
# on the ref Pi to move them here:
#   cat /root/nothere
#   crontab -l
#   find / -writable -type d 2>/dev/null
#   grep -r password /etc 2>/dev/null


def get(command: str) -> str | None:
    """Return canned output for command if in table, else None."""
    return LOOKUP.get(command)
